// DEADLOCK-PRONE: lock order depends on argument order
void transfer(Acct a, Acct b, long amt) {
    a.lock.lock();            // thread1: transfer(1,2) locks 1
    b.lock.lock();            // thread2: transfer(2,1) locks 2 -> circular wait
    try { a.bal -= amt; b.bal += amt; }
    finally { b.lock.unlock(); a.lock.unlock(); }
}

// DEADLOCK-FREE: global order by id, always low id first
void transfer(Acct a, Acct b, long amt) {
    Acct lo = a.id < b.id ? a : b, hi = a.id < b.id ? b : a;
    lo.lock.lock();
    if (lo != hi) hi.lock.lock();
    try { a.bal -= amt; b.bal += amt; }
    finally { if (lo != hi) hi.lock.unlock(); lo.lock.unlock(); }
}

