import java.util.*;
import java.io.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int permits = Integer.parseInt(br.readLine().trim());
        int n = Integer.parseInt(br.readLine().trim());
        int[] w = new int[n];
        if (n > 0) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            for (int i = 0; i < n; i++) w[i] = Integer.parseInt(st.nextToken());
        }
        Semaphore sem = new Semaphore(permits);
        AtomicInteger inFlight = new AtomicInteger(0);
        AtomicInteger maxObserved = new AtomicInteger(0);
        AtomicLong totalWork = new AtomicLong(0);
        CountDownLatch done = new CountDownLatch(n);
        try (ExecutorService ex = Executors.newVirtualThreadPerTaskExecutor()) {
            for (int i = 0; i < n; i++) {
                final int task = w[i];
                ex.submit(() -> {
                    try {
                        sem.acquire();
                        int cur = inFlight.incrementAndGet();
                        maxObserved.accumulateAndGet(cur, Math::max);
                        totalWork.addAndGet(task);
                        inFlight.decrementAndGet();
                    } catch (InterruptedException e) {
                        Thread.currentThread().interrupt();
                    } finally {
                        sem.release();
                        done.countDown();
                    }
                });
            }
            done.await();
        }
        System.out.println(totalWork.get());
        System.out.println("maxConcurrent<=" + permits + " " + (maxObserved.get() <= permits));
    }
}

