import java.util.*;
import java.io.*;
import java.util.concurrent.*;
import java.util.concurrent.locks.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int a = Integer.parseInt(br.readLine().trim());
        int t = Integer.parseInt(br.readLine().trim());
        long[] bal = new long[a];
        StringTokenizer st = new StringTokenizer(br.readLine());
        for (int i = 0; i < a; i++) bal[i] = Long.parseLong(st.nextToken());
        int[] from = new int[t], to = new int[t];
        long[] amt = new long[t];
        for (int i = 0; i < t; i++) {
            StringTokenizer ts = new StringTokenizer(br.readLine());
            from[i] = Integer.parseInt(ts.nextToken());
            to[i] = Integer.parseInt(ts.nextToken());
            amt[i] = Long.parseLong(ts.nextToken());
        }
        ReentrantLock[] locks = new ReentrantLock[a];
        for (int i = 0; i < a; i++) locks[i] = new ReentrantLock();
        try (ExecutorService ex = Executors.newVirtualThreadPerTaskExecutor()) {
            for (int i = 0; i < t; i++) {
                final int f = from[i], d = to[i];
                final long m = amt[i];
                ex.submit(() -> {
                    int lo = Math.min(f, d), hi = Math.max(f, d);
                    locks[lo].lock();
                    if (lo != hi) locks[hi].lock();
                    try {
                        bal[f] -= m;
                        bal[d] += m;
                    } finally {
                        if (lo != hi) locks[hi].unlock();
                        locks[lo].unlock();
                    }
                });
            }
        }
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < a; i++) sb.append(bal[i]).append(i + 1 < a ? ' ' : '\n');
        System.out.print(sb);
    }
}

