import java.util.*;
import java.io.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int shards = Integer.parseInt(br.readLine().trim());
        long lo = Long.parseLong(br.readLine().trim());
        long hi = Long.parseLong(br.readLine().trim());
        LongAdder totalSteps = new LongAdder();
        LongAdder evenLen = new LongAdder();
        long total = hi - lo + 1;
        long chunk = (total + shards - 1) / shards;
        try (ExecutorService ex = Executors.newVirtualThreadPerTaskExecutor()) {
            for (int s = 0; s < shards; s++) {
                final long start = lo + (long) s * chunk;
                if (start > hi) break;
                final long end = Math.min(hi, start + chunk - 1);
                ex.submit(() -> {
                    long localSteps = 0, localEven = 0;
                    for (long v = start; v <= end; v++) {
                        long x = v, steps = 0;
                        while (x != 1) {
                            x = (x % 2 == 0) ? x / 2 : 3 * x + 1;
                            steps++;
                        }
                        localSteps += steps;
                        if (steps % 2 == 0) localEven++;
                    }
                    totalSteps.add(localSteps);
                    evenLen.add(localEven);
                });
            }
        }
        System.out.println("steps " + totalSteps.sum());
        System.out.println("evenLen " + evenLen.sum());
    }
}

