import java.util.*;
import java.io.*;
import java.util.concurrent.*;

public class Main {
    static final long MOD = 1_000_000_007L;

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int q = Integer.parseInt(br.readLine().trim());
        long[] ns = new long[q];
        for (int i = 0; i < q; i++) ns[i] = Long.parseLong(br.readLine().trim());
        List<Future<Long>> futures = new ArrayList<>(q);
        try (ExecutorService ex = Executors.newVirtualThreadPerTaskExecutor()) {
            for (int i = 0; i < q; i++) {
                final long n = ns[i];
                futures.add(ex.submit(() -> fibMod(n)));
            }
            StringBuilder sb = new StringBuilder();
            for (Future<Long> f : futures) sb.append(f.get()).append('\n');
            System.out.print(sb);
        }
    }

    static long fibMod(long n) {
        return fd(n)[0];
    }

    // fast doubling: returns {F(n), F(n+1)} mod MOD
    static long[] fd(long n) {
        if (n == 0) return new long[]{0, 1};
        long[] h = fd(n >> 1);
        long a = h[0], b = h[1];
        long c = (a * ((2 * b % MOD - a + MOD) % MOD)) % MOD;
        long d = (a * a % MOD + b * b % MOD) % MOD;
        if ((n & 1) == 0) return new long[]{c, d};
        else return new long[]{d, (c + d) % MOD};
    }
}
